import{_ as t,c as e,o as d,a7 as a}from"./chunks/framework.DZKVYKRh.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"前端开发/Vue系列/对Vue的理解.md","filePath":"前端开发/Vue系列/对Vue的理解.md"}'),r={name:"前端开发/Vue系列/对Vue的理解.md"},l=a('<div style="text-align:center;"><h1>对Vue的理解</h1></div><ol><li><h2 id="渐进式javascript框架" tabindex="-1">渐进式JavaScript框架 <a class="header-anchor" href="#渐进式javascript框架" aria-label="Permalink to &quot;渐进式JavaScript框架&quot;">​</a></h2><table><tr><td style="width:70px;">含义</td><td>Vue的核心功能是视图模板引擎；Vue作为一个核心库，在视图模板引擎（声明式渲染）的基础上，可以相互独立地添加组件系统、客户端路由、状态管理等构建一个完整的框架</td></tr></table></li><li><h2 id="单页应用-spa-的web应用框架" tabindex="-1">单页应用（SPA）的Web应用框架 <a class="header-anchor" href="#单页应用-spa-的web应用框架" aria-label="Permalink to &quot;单页应用（SPA）的Web应用框架&quot;">​</a></h2><table><tr><td style="width:70px;">含义</td><td>由一个主页面和多个页面片段构成，通过路由切换页面内容，只在初始化时加载主要资源</td></tr><tr><td style="width:70px;">优点</td><td>页面切换时，异步加载数据和更新DOM，响应速度快；局部刷新，内容变化时，整个页面不需要重新加载；良好的前后端分离，分工更明确</td></tr><tr><td style="width:70px;">缺点</td><td>不利于搜索引擎的抓取；首屏渲染速度相对较慢</td></tr></table></li><li><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li><h3 id="数据驱动-mvvm" tabindex="-1">数据驱动（MVVM） <a class="header-anchor" href="#数据驱动-mvvm" aria-label="Permalink to &quot;数据驱动（MVVM）&quot;">​</a></h3></li></ul><table><tr><td style="width:150px;">Model（模型层）</td><td>处理业务逻辑以及和服务端的交互</td></tr><tr><td style="width:150px;">View（视图层）</td><td>将数据模型转化为UI展示</td></tr><tr><td style="width:150px;">View Model（视图模型层）</td><td>连接模型层和视图层，监听模型层数据变化，控制视图层的更新</td></tr></table><ul><li><h3 id="组件化" tabindex="-1">组件化 <a class="header-anchor" href="#组件化" aria-label="Permalink to &quot;组件化&quot;">​</a></h3></li></ul><table><tr><td style="width:70px;">含义</td><td>从UI界面角度划分，把一些UI元素抽离成单个组件，一个.vue文件可以视为一个组件，如弹窗组件、日历组件等</td></tr><tr><td style="width:70px;">优点</td><td>便于UI组件的复用、测试、和维护，降低系统的耦合度</td></tr></table><ul><li><h3 id="指令系统" tabindex="-1">指令系统 <a class="header-anchor" href="#指令系统" aria-label="Permalink to &quot;指令系统&quot;">​</a></h3></li></ul><table><tr><td style="width:150px;">条件渲染指令</td><td>v-if</td></tr><tr><td style="width:150px;">列表渲染指令</td><td>v-for</td></tr><tr><td style="width:150px;">属性绑定指令</td><td>v-bind</td></tr><tr><td style="width:150px;">事件绑定指令</td><td>v-on，只监听自定义事件</td></tr><tr><td style="width:150px;">双向数据绑定指令</td><td>v-model</td></tr></table></li></ol>',2),i=[l];function o(h,s,n,c,u,p){return d(),e("div",null,i)}const x=t(r,[["render",o]]);export{b as __pageData,x as default};
